#include <iostream>
#include <string>

class Book {
private:
    std::string title;
    std::string author;
    std::string isbn;

public:
    Book(const std::string& initialTitle = "", const std::string& initialAuthor = "", const std::string& initialIsbn = "")
        : title(initialTitle), author(initialAuthor), isbn(initialIsbn) {}

    const std::string& getTitle() const {
        return title;
    }

    void setTitle(const std::string& newTitle) {
        title = newTitle;
    }

    const std::string& getAuthor() const {
        return author;
    }

    void setAuthor(const std::string& newAuthor) {
        author = newAuthor;
    }

    const std::string& getIsbn() const {
        return isbn;
    }

    void setIsbn(const std::string& newIsbn) {
        isbn = newIsbn;
    }
};

int main() {
    Book book1("The Great Gatsby", "F. Scott Fitzgerald", "978-0743273565");
    std::cout << "Book 1 Details:\n";
    std::cout << "Title: " << book1.getTitle() << "\n";
    std::cout << "Author: " << book1.getAuthor() << "\n";
    std::cout << "ISBN: " << book1.getIsbn() << "\n";
    std::cout << "---\n";

    Book book2;
    book2.setTitle("1984");
    book2.setAuthor("George Orwell");
    book2.setIsbn("978-0451524935");
    std::cout << "Book 2 Details:\n";
    std::cout << "Title: " << book2.getTitle() << "\n";
    std::cout << "Author: " << book2.getAuthor() << "\n";
    std::cout << "ISBN: " << book2.getIsbn() << "\n";
    std::cout << "---\n";

    Book book3("Valid Title", "Valid Author", "Valid ISBN");
    book3.setTitle("");
    book3.setAuthor(" ");
    book3.setIsbn("");
    std::cout << "Book 3 Details (Robustness Test - Empty/Whitespace Input):\n";
    std::cout << "Title: '" << book3.getTitle() << "'\n";
    std::cout << "Author: '" << book3.getAuthor() << "'\n";
    std::cout << "ISBN: '" << book3.getIsbn() << "'\n";
    std::cout << "---\n";

    Book book4("", "", "");
    std::cout << "Book 4 Details (Robustness Test - Empty Constructor Input):\n";
    std::cout << "Title: '" << book4.getTitle() << "'\n";
    std::cout << "Author: '" << book4.getAuthor() << "'\n";
    std::cout << "ISBN: '" << book4.getIsbn() << "'\n";
    std::cout << "---\n";

    return 0;
}
